// Bridge to the legacy showToast() in app.js. During the migration we want
// notifications to stay visually consistent, so islands defer to the global
// helper instead of rendering their own toasts. If app.js hasn't loaded yet
// (or the function has been renamed), we fall back to console so a missing
// toast doesn't swallow the user-facing message.

type ToastType = "info" | "success" | "warning" | "error";

declare global {
  // eslint-disable-next-line no-var
  var showToast:
    | ((title: string, message: string, type?: ToastType, duration?: number) => void)
    | undefined;
}

export function toast(
  title: string,
  message: string,
  type: ToastType = "info",
  duration = 5000,
): void {
  if (typeof window.showToast === "function") {
    window.showToast(title, message, type, duration);
    return;
  }
  // eslint-disable-next-line no-console
  console.warn(`[toast:${type}] ${title} — ${message}`);
}
